function downloadFile(url, onComplete) {
  console.log(`Starting download from ${url}...`);

  // Simulate a 2-second network request
  setTimeout(() => {
    const fileContent = '...file data...';
    console.log('Download finished.');

    // Invoke the callback with the result
    onComplete(fileContent);
  }, 2000);
}

console.log('1. User clicks download');
downloadFile('https://example.com/data.txt', (data) => {
  console.log('3. Displaying data:', data);
});
console.log('2. User can keep scrolling');

// Output:
// 1. User clicks download
// Starting download from https://example.com/data.txt...
// 2. User can keep scrolling
// Download finished. (2 seconds later)
// 3. Displaying data: ...file data...

